    "component_interactions": [
      {
        "from": "application (dual-write, Step 2)",
        "to": "users.preferences_json + user_preferences table",
        "status": "risk",
        "issue": "During Step 3 backfill, a race condition exists: if a user updates preferences AFTER the backfill cursor has passed them but BEFORE backfill completes, the dual-write correctly updates user_preferences. However, if backfill has NOT yet reached a user and that user updates preferences, the dual-write writes to user_preferences, then the backfill overwrites it with the STALE value from users.preferences_json. Backfill must use a WHERE NOT EXISTS or updated_at comparison to avoid clobbering fresher dual-written data."
      },
      {
        "from": "application (read switch, Step 4 rolling deploy)",
        "to": "user_preferences table",
        "status": "broken",
        "issue": "During rolling deployment, Instance 1 reads from user_preferences while Instances 2 and 3 still read from users.preferences_json. If the backfill was incomplete (no validation gate), Instance 1 returns NULL or default preferences for users whose rows were never copied. This is a data-loss-equivalent bug visible to end users — preferences silently disappear for affected users."
      },
      {
        "from": "backfill job (Step 3)",
        "to": "user_preferences table",
        "status": "risk",
        "issue": "Backfill has no progress tracking or resumability. If it fails at row 500,000 of 2,000,000, the operator must either re-run from scratch (doubling write load and risking the overwrite race again) or manually determine where it stopped. This is an operational nightmare at scale."
      }
    ],
    "contract_compliance": "The implicit contract — that every user's preferences exist in user_preferences before any instance reads from it — is NOT enforced by any validation gate between Steps 3 and 4. The plan relies on human judgment that the backfill 'worked' with no tooling to verify.",
    "data_flow_integrity": "COMPROMISED. Three integrity gaps: (1) backfill can overwrite newer dual-written data with stale JSON blob data, (2) incomplete backfill causes silent preference loss for end users, (3) during rolling deploy there is no consistency guarantee — the same user hitting different instances may see different preference values."
  },

  "observability_review": {
    "logging": {
      "coverage": "missing",
      "gaps": [
        "No logging mentioned for dual-write success/failure divergence between old and new tables",
        "No logging for backfill progress, skip count, or error count",
        "No logging to detect which read source each instance is using during rolling deploy"
      ]
    },
    "metrics": {
      "coverage": "missing",
      "gaps": [
        "No metric to compare row counts between users table and user_preferences table",
        "No metric tracking dual-write latency overhead",
        "No metric for preference-read misses (user exists but no row in user_preferences)",
        "No metric to detect preference value divergence between old and new stores"
      ]
    },
    "tracing": {
      "coverage": "missing",
      "gaps": [
        "No trace context to identify which storage backend served a given preference read",
        "No trace correlation between backfill job operations and concurrent user writes"
      ]
    },
    "debugging_capability": "Extremely poor. If a user reports 'my preferences reset,' the on-call engineer has no way to determine: (a) whether the backfill copied that user's data, (b) whether a race condition overwrote it, or (c) whether the instance serving that user had already switched read sources. Debugging this at 3am would require direct database queries comparing both tables row by row."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Backfill job crashes midway through processing",
        "handling": "unhandled",
        "recommendation": "Add cursor-based checkpointing (e.g., store last processed user_id). On restart, resume from checkpoint. Use idempotent upserts with a WHERE clause like 'INSERT ... ON CONFLICT DO UPDATE ... WHERE user_preferences.updated_at < excluded.updated_at' to avoid overwriting fresher data on re-runs."
      },
      {
        "scenario": "Backfill overwrites dual-written data with stale JSON blob",
        "handling": "unhandled",
        "recommendation": "Backfill INSERT must include a staleness guard: only write if no row exists OR if the existing row's updated_at is older than the JSON blob's last-modified timestamp. Simplest safe approach: INSERT ... ON CONFLICT (user_id) DO NOTHING."
      },
      {
        "scenario": "Rolling deploy in Step 4 — mixed read sources across instances",
        "handling": "unhandled",
        "recommendation": "Use a feature flag (even a simple database or config flag) to switch all instances atomically. Alternatively, deploy code that reads from user_preferences with a fallback to users.preferences_json when no row is found — this makes the rolling deploy safe regardless of backfill completeness."
      },
      {
        "scenario": "Step 4 deployed but backfill was incomplete — some users have no row in user_preferences",
        "handling": "unhandled",
        "recommendation": "Add a mandatory validation gate between Steps 3 and 4: run a query like SELECT COUNT(*) FROM users u LEFT JOIN user_preferences up ON u.id = up.user_id WHERE up.user_id IS NULL — if count > 0, block Step 4."
      },
      {
        "scenario": "Need to rollback from Step 4 to Step 3 (revert read source)",
        "handling": "partial",
        "recommendation": "Rollback is possible because dual-write is still active, but it requires redeploying the previous application version across all instances. Document this explicitly as the rollback plan and test it."
      }
    ],
    "retry_config": "Not specified. Backfill job has no retry or resume capability for transient database errors during bulk copy.",
    "timeout_config": "Not specified. No timeout on backfill job — a long-running backfill could hold connections or locks for extended periods depending on implementation.",
    "circuit_breakers": "None. No circuit breaker between dual-write paths — if the new table becomes unavailable, writes to it fail without fallback.",
    "graceful_degradation": "Absent. The critical missing pattern is a read-fallback: Step 4 code should read from user_preferences, and if no row is found, fall back to users.preferences_json. This single change makes the entire migration safe against incomplete backfills and rolling deploy inconsistency."
  },

